class Solution:
    def secondHighest(self, s):
        digits = []
        for ch in s:
            if ch.isdigit():
                digits.append(int(ch))
        uniq = sorted(set(digits), reverse=True)
        return uniq[1] if len(uniq) >= 2 else -1

