var secondHighest = function(s) {
    let first = -1, second = -1;
    for (const ch of s) {
        if (ch >= '0' && ch <= '9') {
            const d = ch.charCodeAt(0) - 48;
            if (d > first) {
                second = first;
                first = d;
            } else if (d < first && d > second) {
                second = d;
            }
        }
    }
    return second;
};
